// Regenerates src/flag-assets.gen.ts from the ISO3_TO_2 map in src/flags.ts:
// one bundled flag-icons SVG per distinct alpha-2 code, so the build ships
// exactly the nations that can appear in draws (not the full 270-flag set).
//   node scripts/gen-flag-assets.mjs
// (Parses flags.ts textually rather than importing it, so it has no dependency
// on the generated file existing yet.)
import fs from "node:fs";
import path from "node:path";

const root = path.join(import.meta.dirname, "..");
const src = fs.readFileSync(path.join(root, "src/flags.ts"), "utf8");
const map = src.match(/const ISO3_TO_2[^{]*\{([\s\S]*?)\};/);
if (!map) throw new Error("ISO3_TO_2 map not found in src/flags.ts");
const codes = [...new Set([...map[1].matchAll(/:\s*"([A-Z]{2})"/g)].map((m) => m[1]))].sort();

const missing = codes.filter((c) => !fs.existsSync(path.join(root, `node_modules/flag-icons/flags/4x3/${c.toLowerCase()}.svg`)));
if (missing.length) throw new Error(`flag-icons has no 4x3 asset for: ${missing.join(", ")}`);

const out =
  `// AUTO-GENERATED by scripts/gen-flag-assets.mjs — do not edit by hand.\n` +
  `// One bundled SVG per alpha-2 code in flags.ts ISO3_TO_2 (${codes.length} flags), so the\n` +
  `// bundle stays bounded to nations that actually appear in Grand Slam draws.\n` +
  codes.map((c) => `import ${c} from "flag-icons/flags/4x3/${c.toLowerCase()}.svg";`).join("\n") +
  `\n\nexport const FLAG_URLS: Record<string, string> = {\n  ` +
  codes.join(", ") +
  `,\n};\n`;

fs.writeFileSync(path.join(root, "src/flag-assets.gen.ts"), out);
console.log(`wrote src/flag-assets.gen.ts (${codes.length} flags)`);
